public void insert(boolean _defaultRelatedTables)
{
    this.updateMatchingStatus();
    next insert(_defaultRelatedTables);
}

    public void update()
    {
        this.updateMatchingStatus();
        this.updateWarrantyRetention();

        next update();
    }

    public void updateMatchingStatus()
    {
        UBSVendInvoiceBankInfoMatchingStatus matchingStatus = UBSVendInvoiceBankInfoMatchingStatus::Success;
        VendBankAccount vendBankAccount;

        vendBankAccount = VendBankAccount::find(this.InvoiceAccount, this.VendBankAccountID);

        if(this.UBSBankIBAN != "")
        {
            if(vendBankAccount.BankIBAN != this.UBSBankIBAN || vendBankAccount.SWIFTNo != this.UBSSWIFTNo)
            {
                matchingStatus = UBSVendInvoiceBankInfoMatchingStatus::Error;
            }
        }
        else
        {
            if(vendBankAccount.AccountNum != this.UBSAccountNum || vendBankAccount.SWIFTNo != this.UBSSWIFTNo)
            {
                matchingStatus = UBSVendInvoiceBankInfoMatchingStatus::Error;
            }
        }

        this.UBSBankInfoMatchingStatus = matchingStatus;
    }

    public void updateWarrantyRetention()
    {
        if(this.PurchId != "" && this.UBSIsPurchWarrantyImported == NoYes::No)
        {
            PurchTable purchTable = PurchTable::find(this.PurchId);

            if(purchTable)
            {
                this.UBSHasWarrantyRetention = purchTable.UBSIsHoldbackApplied;
                this.UBSWarrantyRate = purchTable.UBSHoldbackPercentage;

                this.UBSIsPurchWarrantyImported = NoYes::Yes;
            }
        }
    }
